// We weten in welke ronde van de loop we zitten (0, 1, 2...)
const index = $runIndex;

// We grijpen terug naar de 'If' node, want die had de PDF nog wel!
const originalItem = $('📂 Check: Is PDF/Image?').all()[index];

// Maak het unieke ID
const invoiceId = `${originalItem.json.id || 'msg'}-${Date.now()}`;

// Geef de data terug, INCLUSIEF de geredde PDF (binary)
return [
  {
    json: {
      ...originalItem.json,
      invoiceId
    },
    binary: originalItem.binary 
  }
];

// 1. Haal ID op (met fallback)
let invoiceId = "MISSING_ID";
try {
    invoiceId = $('🆔 Set Context & Binary').item.json.invoiceId;
} catch (e) {
    invoiceId = $json.invoiceId || "UNKNOWN_ID";
}

// 2. Veilig de AI output ophalen
const aiOutput = $input.item.json.output || $input.item.json.text || $input.item.json.response || "";

let data = null;
let parseStatus = "OK";

try {
  // Schoonmaken van Markdown
  let clean = aiOutput.toString()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  data = JSON.parse(clean);
} catch (e) {
  // Parsen mislukt
  data = null;
}

// --- DE FIX: Check of data wel een object is ---
// Als JSON.parse 'null' teruggaf, of als het mislukte, vullen we de nood-data in.
if (!data || typeof data !== 'object') {
    parseStatus = "AI_PARSE_ERROR";
    data = {
        leverancier: "⚠️ Fout bij AI",
        factuurdatum: null,
        totaalbedrag: 0,
        btw_bedrag: 0,
        factuurnummer: "Zie PDF",
        valuta: "EUR"
    };
}

// 3. Normaliseren (String "null" naar echte null)
// Nu kunnen we veilig loopen, want 'data' is gegarandeerd een object
for (const key of Object.keys(data)) {
  if (data[key] === "null") data[key] = null;
}

// 4. Data validatie & Types
const leverancier = (typeof data.leverancier === "string" && data.leverancier.trim()) 
    ? data.leverancier.trim() 
    : "Onbekend";

let totaalbedrag = data.totaalbedrag;
if (typeof totaalbedrag === 'string') {
    totaalbedrag = parseFloat(totaalbedrag.replace(',', '.'));
}
if (!totaalbedrag || isNaN(totaalbedrag)) {
    totaalbedrag = 0;
}

// 5. Output
return [
  {
    json: {
      invoiceId: invoiceId,
      ai_parse_status: parseStatus,
      ai_raw_debug: aiOutput, 
      leverancier: leverancier,
      factuurdatum: data.factuurdatum || null,
      totaalbedrag: totaalbedrag,
      btw_bedrag: data.btw_bedrag || 0,
      factuurnummer: data.factuurnummer || "Zie PDF",
      valuta: data.valuta || "EUR"
    }
  }
];

// 1. We halen de data direct bij de BRON (niet wachten op Airtable)

// De link halen we op bij de Google Drive node
// (Zorg dat de node naam exact '☁️ Google Drive: Backup' is, zoals in je screenshot)
const driveLink = $('☁️ Google Drive: Backup').item.json.webViewLink || "https://google.com";

// De bedragen en naam halen we op bij de AI Code node
const aiData = $('🧹 Code: Normalize & Clean').item.json;
const bedrag = aiData.totaalbedrag || 0;
const leverancier = aiData.leverancier || "Onbekend";

// Het ID hebben we wel uit de huidige stap nodig (want dat is het ID van de nieuwe rij)
const recordId = $json.id || "error_id";

// 2. Bouw de blokken
const slackBlocks = [
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      // Hier staat nu 'Bekijk factuur' en de variabelen komen direct van de bron
      "text": `*💰 Nieuwe Factuur: € ${bedrag}*\nLeverancier: ${leverancier}\n<${driveLink}|Bekijk factuur>`
    }
  },
  {
    "type": "actions",
    "elements": [
      {
        "type": "button",
        "text": {
          "type": "plain_text",
          "text": "✅ Goedkeuren"
        },
        "style": "primary",
        "value": `approve__${recordId}`,
        "action_id": "approve_invoice"
      },
      {
        "type": "button",
        "text": {
          "type": "plain_text",
          "text": "❌ Afwijzen"
        },
        "style": "danger",
        "value": `reject__${recordId}`,
        "action_id": "reject_invoice"
      }
    ]
  }
];

// 3. Return het resultaat
return [
  {
    json: {
      slack_blocks: slackBlocks
    }
  }
];

