const data = $input.item.json;

// Haal bedrag en BTW op
let totaalBedrag = parseFloat(data.Bedrag) || 0;
let btwBedrag = parseFloat(data.BTW) || 0;

// Bereken het bedrag EXCLUSIEF BTW
let bedragExclBtw = (totaalBedrag - btwBedrag).toFixed(2);

// Datum formatteren
const datum = data.Datum || new Date().toISOString().split('T')[0];

// Leveranciersnaam
const naam = (data['Naam (from Leverancier)'] && data['Naam (from Leverancier)'][0]) || 'Onbekend';

// Factuurnummer
const factuurnummer = data.Factuurnummer || 'Geen kenmerk';

// De volledige body zoals Moneybird die wil
const body = {
  purchase_invoice: {
    contact_id: "475440760197481862", // Let op: deze staat nu hardcoded
    reference: factuurnummer,
    date: datum,
    details_attributes: [
      {
        description: `Factuur van ${naam}`,
        price: bedragExclBtw,
        tax_rate_id: "475257263575008816"
      }
    ]
  }
};

// n8n verwacht een array van objecten met een 'json' sleutel
return [{ json: body }];
